## Common patterns

### Skip to main content

A standard accessibility pattern for keyboard navigation.

```jsx live-dev
const App = () => {
  const mainContentRef = React.useRef<HTMLDivElement>(null);

  const handleSkip = () => {
    mainContentRef.current?.focus();
  };

  return (
    <Stack gap="400">
      <VisuallyHidden isFocusable>
        <Button onClick={handleSkip}>Skip to main content</Button>
      </VisuallyHidden>

      <Box p="400" bg="neutral.7" borderRadius="md">
        <Text fontWeight="bold">Navigation Area</Text>
        <Text textStyle="sm" color="neutral.11">
          Press Tab to reveal the skip link
        </Text>
      </Box>

      <Box 
        ref={mainContentRef}
        tabIndex={-1}
        p="400" 
        bg="primary.7" 
        borderRadius="md"
      >
        <Text fontWeight="bold" mb="200">Main Content</Text>
        <Text>This is the main content area that users can skip to.</Text>
      </Box>
    </Stack>
  );
};
```

### Accessible data tables

Provide additional context for screen reader users navigating tables.

```jsx live-dev
const App = () => {
  const data = [
    { product: 'Widget A', price: 29.99, stock: 45 },
    { product: 'Widget B', price: 39.99, stock: 12 },
    { product: 'Widget C', price: 19.99, stock: 0 },
  ];

  return (
    <Box overflowX="auto">
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr>
            <th style={{ textAlign: 'left', padding: '12px', borderBottom: '2px solid #e2e8f0' }}>
              Product
            </th>
            <th style={{ textAlign: 'right', padding: '12px', borderBottom: '2px solid #e2e8f0' }}>
              Price
            </th>
            <th style={{ textAlign: 'right', padding: '12px', borderBottom: '2px solid #e2e8f0' }}>
              Stock
            </th>
          </tr>
        </thead>
        <tbody>
          {data.map((item, index) => (
            <tr key={index}>
              <td style={{ padding: '12px', borderBottom: '1px solid #e2e8f0' }}>
                {item.product}
              </td>
              <td style={{ textAlign: 'right', padding: '12px', borderBottom: '1px solid #e2e8f0' }}>
                <VisuallyHidden as="span">Price: </VisuallyHidden>
                ${item.price.toFixed(2)}
              </td>
              <td style={{ textAlign: 'right', padding: '12px', borderBottom: '1px solid #e2e8f0' }}>
                <VisuallyHidden as="span">Stock: </VisuallyHidden>
                {item.stock === 0 ? (
                  <span style={{ color: '#ef4444' }}>
                    Out of stock
                    <VisuallyHidden as="span"> for {item.product}</VisuallyHidden>
                  </span>
                ) : (
                  item.stock
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </Box>
  );
};
```

### Form field descriptions

Provide additional hints for form fields without cluttering the UI.

```jsx live-dev
const App = () => {
  const [password, setPassword] = React.useState('');

  return (
    <Stack gap="400">
      <Box>
        <Text as="label" fontWeight="semibold" mb="200" display="block">
          Password
        </Text>
        <input
          type="password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          aria-describedby="password-hint"
          style={{
            width: '100%',
            padding: '8px 12px',
            borderRadius: '4px',
            border: '1px solid #cbd5e0',
          }}
        />
        <VisuallyHidden id="password-hint">
          Password must be at least 8 characters long and contain a number
        </VisuallyHidden>
        <Text textStyle="sm" color="neutral.11" mt="100">
          Min. 8 characters
        </Text>
      </Box>
    </Stack>
  );
};
```

### Loading states

Announce loading states to screen reader users.

```jsx live-dev
const App = () => {
  const [isLoading, setIsLoading] = React.useState(false);
  const [data, setData] = React.useState<string | null>(null);

  const loadData = () => {
    setIsLoading(true);
    setData(null);

    setTimeout(() => {
      setData('Data loaded successfully!');
      setIsLoading(false);
    }, 2000);
  };

  return (
    <Stack gap="400">
      <Button onClick={loadData} isDisabled={isLoading}>
        {isLoading ? 'Loading...' : 'Load Data'}
      </Button>

      <VisuallyHidden role="status" aria-live="polite" aria-atomic="true">
        {isLoading ? 'Loading data, please wait' : ''}
        {data ? 'Data loaded successfully' : ''}
      </VisuallyHidden>

      {data && (
        <Box p="400" bg="success.7" borderRadius="md">
          <Text>{data}</Text>
        </Box>
      )}
    </Stack>
  );
};
```

## Testing your implementation

These examples demonstrate how to test your implementation when using VisuallyHidden within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Usage Tests

Verify the VisuallyHidden component hides content visually while keeping it accessible

```tsx
import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import { VisuallyHidden, NimbusProvider, Button } from "@commercetools/nimbus";

describe("VisuallyHidden - Basic usage", () => {
  it("renders content that is accessible but visually hidden", () => {
    render(
      <NimbusProvider>
        <VisuallyHidden data-testid="hidden-content">
          Screen reader only text
        </VisuallyHidden>
      </NimbusProvider>
    );

    const element = screen.getByTestId("hidden-content");
    expect(element).toBeInTheDocument();
    expect(element).toHaveTextContent("Screen reader only text");

    // Verify it's visually hidden
    const styles = window.getComputedStyle(element);
    expect(styles.position).toBe("absolute");
    expect(styles.width).toBe("1px");
    expect(styles.height).toBe("1px");
  });

  it("renders as div by default and as span when specified", () => {
    const { rerender } = render(
      <NimbusProvider>
        <VisuallyHidden data-testid="element">Content</VisuallyHidden>
      </NimbusProvider>
    );

    expect(screen.getByTestId("element").tagName).toBe("DIV");

    rerender(
      <NimbusProvider>
        <VisuallyHidden as="span" data-testid="element">
          Content
        </VisuallyHidden>
      </NimbusProvider>
    );

    expect(screen.getByTestId("element").tagName).toBe("SPAN");
  });

  it("supports skip navigation with isFocusable", () => {
    render(
      <NimbusProvider>
        <VisuallyHidden isFocusable>
          <Button data-testid="skip-button">Skip to content</Button>
        </VisuallyHidden>
      </NimbusProvider>
    );

    expect(screen.getByTestId("skip-button")).toBeInTheDocument();
  });
});
```

### Accessibility Tests

Verify ARIA attributes and accessibility patterns

```tsx
import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import { VisuallyHidden, NimbusProvider, Button } from "@commercetools/nimbus";

describe("VisuallyHidden - Accessibility", () => {
  it("forwards ARIA attributes for live regions", () => {
    render(
      <NimbusProvider>
        <VisuallyHidden
          role="status"
          aria-live="polite"
          data-testid="status-region"
        >
          Loading complete
        </VisuallyHidden>
      </NimbusProvider>
    );

    const element = screen.getByTestId("status-region");
    expect(element).toHaveAttribute("role", "status");
    expect(element).toHaveAttribute("aria-live", "polite");
  });

  it("can be used with aria-describedby for form hints", () => {
    render(
      <NimbusProvider>
        <input
          type="text"
          aria-describedby="field-hint"
          data-testid="input-field"
        />
        <VisuallyHidden id="field-hint">
          Enter your full name as it appears on your ID
        </VisuallyHidden>
      </NimbusProvider>
    );

    const input = screen.getByTestId("input-field");
    expect(input).toHaveAttribute("aria-describedby", "field-hint");
  });

  it("provides accessible labels for icon buttons", () => {
    render(
      <NimbusProvider>
        <Button data-testid="icon-button">
          <span aria-hidden="true">⚙️</span>
          <VisuallyHidden>Settings</VisuallyHidden>
        </Button>
      </NimbusProvider>
    );

    const button = screen.getByTestId("icon-button");
    expect(button).toHaveTextContent("Settings");
  });
});
```


